import { useState, useRef, useEffect, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { Send, Trash2, Loader2, Palette, User, Square, Eye, Download, Code, ArrowLeft } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { ScrollArea } from "@/components/ui/scroll-area";
import { useMenuDesigner } from "@/hooks/useMenuDesigner";
import ReactMarkdown from "react-markdown";
import { toast } from "sonner";

const QUICK_QUESTIONS = [
  "帮我设计一份中餐菜单",
  "Menu do dia 套餐设计",
  "设计一份日料菜单",
  "菜品定价策略建议",
  "菜单多语言翻译",
  "过敏原标注指南",
];

/** Extract ```html-menu ... ``` blocks from markdown content */
function extractHtmlMenus(content: string): { html: string; before: string; after: string }[] {
  const results: { html: string; before: string; after: string }[] = [];
  const regex = /```html-menu\n([\s\S]*?)```/g;
  let lastIndex = 0;
  let match;

  while ((match = regex.exec(content)) !== null) {
    results.push({
      before: content.slice(lastIndex, match.index),
      html: match[1].trim(),
      after: "",
    });
    lastIndex = regex.lastIndex;
  }

  if (results.length > 0) {
    results[results.length - 1].after = content.slice(lastIndex);
  }

  return results;
}

function MenuPreview({ html }: { html: string }) {
  const [showPreview, setShowPreview] = useState(true);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const handleDownload = () => {
    const blob = new Blob([html], { type: "text/html;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `menu-design-${Date.now()}.html`;
    a.click();
    URL.revokeObjectURL(url);
    toast.success("菜单已下载");
  };

  const handleCopyHtml = () => {
    navigator.clipboard.writeText(html);
    toast.success("HTML 代码已复制");
  };

  return (
    <div className="my-4 border rounded-lg overflow-hidden bg-card">
      <div className="flex items-center justify-between px-3 py-2 bg-muted/50 border-b">
        <span className="text-xs font-medium text-muted-foreground flex items-center gap-1.5">
          <Palette className="h-3.5 w-3.5" />
          菜单设计成品
        </span>
        <div className="flex items-center gap-1">
          <Button
            variant={showPreview ? "default" : "outline"}
            size="sm"
            className="h-7 text-xs px-2"
            onClick={() => setShowPreview(true)}
          >
            <Eye className="h-3 w-3 mr-1" />
            预览
          </Button>
          <Button
            variant={!showPreview ? "default" : "outline"}
            size="sm"
            className="h-7 text-xs px-2"
            onClick={() => setShowPreview(false)}
          >
            <Code className="h-3 w-3 mr-1" />
            代码
          </Button>
          <Button variant="outline" size="sm" className="h-7 text-xs px-2" onClick={handleCopyHtml}>
            复制
          </Button>
          <Button variant="outline" size="sm" className="h-7 text-xs px-2" onClick={handleDownload}>
            <Download className="h-3 w-3 mr-1" />
            下载
          </Button>
        </div>
      </div>

      {showPreview ? (
        <iframe
          ref={iframeRef}
          srcDoc={html}
          className="w-full border-0"
          style={{ minHeight: "600px", maxHeight: "900px" }}
          sandbox="allow-same-origin"
          title="Menu Preview"
          onLoad={() => {
            if (iframeRef.current?.contentDocument) {
              const h = iframeRef.current.contentDocument.documentElement.scrollHeight;
              iframeRef.current.style.height = Math.min(Math.max(h + 20, 400), 900) + "px";
            }
          }}
        />
      ) : (
        <ScrollArea className="max-h-[400px]">
          <pre className="p-4 text-xs font-mono whitespace-pre-wrap break-all text-muted-foreground">
            {html}
          </pre>
        </ScrollArea>
      )}
    </div>
  );
}

function AssistantMessage({ content }: { content: string }) {
  const segments = useMemo(() => extractHtmlMenus(content), [content]);

  if (segments.length === 0) {
    return (
      <div className="prose prose-sm dark:prose-invert max-w-none">
        <ReactMarkdown>{content}</ReactMarkdown>
      </div>
    );
  }

  return (
    <div>
      {segments.map((seg, i) => (
        <div key={i}>
          {seg.before.trim() && (
            <div className="prose prose-sm dark:prose-invert max-w-none">
              <ReactMarkdown>{seg.before}</ReactMarkdown>
            </div>
          )}
          <MenuPreview html={seg.html} />
          {seg.after.trim() && (
            <div className="prose prose-sm dark:prose-invert max-w-none">
              <ReactMarkdown>{seg.after}</ReactMarkdown>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

const MerchantMenuDesigner = () => {
  const { t } = useTranslation();
  const [input, setInput] = useState("");
  const scrollAreaRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const {
    messages,
    isLoading,
    isLoadingHistory,
    sendMessage,
    clearChat,
    stopGeneration,
    loadChatHistory,
  } = useMenuDesigner();

  useEffect(() => {
    loadChatHistory();
  }, [loadChatHistory]);

  useEffect(() => {
    if (scrollAreaRef.current) {
      scrollAreaRef.current.scrollTop = scrollAreaRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;
    sendMessage(input.trim());
    setInput("");
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSubmit(e);
    }
  };

  const handleQuickQuestion = (question: string) => {
    sendMessage(question);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-8rem)] max-w-4xl mx-auto p-4">
      {/* Header */}
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-3">
          <div className="p-2 rounded-lg bg-violet-100 dark:bg-violet-900/30">
            <Palette className="h-6 w-6 text-violet-600" />
          </div>
          <div>
            <h1 className="text-xl font-bold">菜单设计师</h1>
            <p className="text-sm text-muted-foreground">专业菜单设计与策划 · 可直接生成精美菜单</p>
          </div>
        </div>
        <Button variant="outline" size="sm" onClick={clearChat} disabled={messages.length === 0 && !isLoading}>
          <Trash2 className="h-4 w-4 mr-1" />
          清空
        </Button>
      </div>

      {/* Messages */}
      <ScrollArea className="flex-1 border rounded-lg p-4 mb-4" ref={scrollAreaRef}>
        <div className="space-y-4">
          {isLoadingHistory && (
            <div className="text-center py-4">
              <Loader2 className="h-5 w-5 animate-spin mx-auto text-muted-foreground" />
              <p className="text-sm text-muted-foreground mt-2">加载历史记录...</p>
            </div>
          )}

          {!isLoadingHistory && messages.length === 0 && (
            <div className="text-center py-8">
              <Palette className="h-12 w-12 mx-auto mb-4 text-violet-500/50" />
              <p className="text-lg font-medium mb-2">您好！我是您的专属菜单设计师</p>
              <p className="text-sm text-muted-foreground mb-2">
                我不仅提供策略建议，更能<strong>直接生成精美的 HTML 菜单设计成品</strong>
              </p>
              <p className="text-xs text-muted-foreground mb-6">
                支持多语言翻译、过敏原标注、A4 印刷排版 · 可下载 HTML 文件直接使用
              </p>
              <div className="flex flex-wrap gap-2 justify-center max-w-lg mx-auto">
                {QUICK_QUESTIONS.map((q) => (
                  <Button
                    key={q}
                    variant="outline"
                    size="sm"
                    onClick={() => handleQuickQuestion(q)}
                    className="text-xs"
                  >
                    {q}
                  </Button>
                ))}
              </div>
            </div>
          )}

          {messages.map((message, index) => (
            <div
              key={index}
              className={`flex gap-3 ${message.role === "user" ? "justify-end" : "justify-start"}`}
            >
              {message.role === "assistant" && (
                <div className="w-8 h-8 rounded-full bg-violet-100 dark:bg-violet-900/30 flex items-center justify-center flex-shrink-0">
                  <Palette className="h-4 w-4 text-violet-600" />
                </div>
              )}
              <div
                className={`max-w-[90%] rounded-lg px-4 py-2 ${
                  message.role === "user"
                    ? "bg-primary text-primary-foreground"
                    : "bg-muted"
                }`}
              >
                {message.role === "assistant" ? (
                  message.content ? (
                    <AssistantMessage content={message.content} />
                  ) : (
                    <div className="flex items-center gap-2 py-1">
                      <Loader2 className="h-4 w-4 animate-spin" />
                      <span className="text-sm text-muted-foreground">正在设计中...</span>
                    </div>
                  )
                ) : (
                  <p className="whitespace-pre-wrap">{message.content}</p>
                )}
              </div>
              {message.role === "user" && (
                <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center flex-shrink-0">
                  <User className="h-4 w-4 text-primary" />
                </div>
              )}
            </div>
          ))}
        </div>
      </ScrollArea>

      {/* Input */}
      <form onSubmit={handleSubmit} className="flex gap-2">
        <Textarea
          ref={textareaRef}
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="描述您的菜单设计需求，如：帮我设计一份高端中餐菜单，餐厅在里斯本，主打川菜..."
          disabled={isLoading}
          className="flex-1 min-h-[44px] max-h-[120px] resize-none"
          rows={1}
        />
        {isLoading ? (
          <Button type="button" variant="outline" size="icon" onClick={stopGeneration}>
            <Square className="h-4 w-4" />
          </Button>
        ) : (
          <Button type="submit" size="icon" disabled={!input.trim()}>
            <Send className="h-4 w-4" />
          </Button>
        )}
      </form>
    </div>
  );
};

export default MerchantMenuDesigner;
