import { useState, useRef, useCallback } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { useAIChatHistory } from "@/hooks/useAIChatHistory";
import { toast } from "sonner";

type Message = { role: "user" | "assistant"; content: string };

const CHAT_URL = `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/menu-designer`;

export const useMenuDesigner = () => {
  const { user } = useAuth();
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const abortControllerRef = useRef<AbortController | null>(null);
  const { loadMessages, saveMessage, clearHistory, isLoadingHistory } = useAIChatHistory("menu-designer");

  const loadChatHistory = useCallback(async () => {
    const history = await loadMessages();
    if (history.length > 0) {
      setMessages(history);
    }
  }, [loadMessages]);

  const sendMessage = useCallback(async (input: string) => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { role: "user", content: input.trim() };
    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    saveMessage("user", input.trim());

    const assistantMsg: Message = { role: "assistant", content: "" };
    setMessages(prev => [...prev, assistantMsg]);

    let fullContent = "";

    try {
      abortControllerRef.current = new AbortController();

      const resp = await fetch(CHAT_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY}`,
        },
        body: JSON.stringify({
          messages: [...messages, userMsg],
          merchantUserId: user?.id || null,
        }),
        signal: abortControllerRef.current.signal,
      });

      if (!resp.ok) {
        const errorData = await resp.json().catch(() => ({}));
        if (resp.status === 429) {
          toast.error("请求过于频繁，请稍后再试");
        } else if (resp.status === 402) {
          toast.error("AI服务额度不足");
        }
        throw new Error(errorData.error || `请求失败: ${resp.status}`);
      }

      const reader = resp.body?.getReader();
      if (!reader) throw new Error("无法读取响应流");

      const decoder = new TextDecoder();
      let buffer = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n");
        buffer = lines.pop() || "";

        for (const line of lines) {
          if (!line.startsWith("data: ")) continue;
          const jsonStr = line.slice(6).trim();
          if (jsonStr === "[DONE]") continue;

          try {
            const parsed = JSON.parse(jsonStr);
            const content = parsed.choices?.[0]?.delta?.content;
            if (content) {
              fullContent += content;
              setMessages(prev => {
                const updated = [...prev];
                const last = updated[updated.length - 1];
                if (last?.role === "assistant") {
                  last.content = fullContent;
                }
                return [...updated];
              });
            }
          } catch {
            // ignore parse errors
          }
        }
      }

      if (fullContent) {
        saveMessage("assistant", fullContent);
      }
    } catch (error) {
      if ((error as Error).name === "AbortError") return;

      setMessages(prev => {
        const updated = [...prev];
        const last = updated[updated.length - 1];
        if (last?.role === "assistant" && !last.content) {
          last.content = `错误: ${(error as Error).message}`;
        }
        return [...updated];
      });
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  }, [messages, isLoading, user?.id, saveMessage]);

  const clearChat = useCallback(async () => {
    abortControllerRef.current?.abort();
    setMessages([]);
    setIsLoading(false);
    await clearHistory();
  }, [clearHistory]);

  const stopGeneration = useCallback(() => {
    abortControllerRef.current?.abort();
    setIsLoading(false);
  }, []);

  return {
    messages,
    isLoading,
    isLoadingHistory,
    sendMessage,
    clearChat,
    stopGeneration,
    loadChatHistory,
  };
};
